example.code:
resource "azurerm_subnet" "appgw" {
  name                 = "appgw"
  resource_group_name  = azurerm_resource_group.spoke.name
  virtual_network_name = azurerm_virtual_network.spoke.name
  address_prefixes     = ["10.1.0.0/24"]

  delegation {
    name = "appgw-delegation"
    service_delegation {
      name = "Microsoft.Network/applicationGateways"
    }
  }
}

# Creates only hub → spoke. Traffic fails from spoke back to hub.
resource "azurerm_virtual_network_peering" "hub_to_spoke" {
  name                      = "hub-to-prod"
  virtual_network_name      = azurerm_virtual_network.hub.name
  remote_virtual_network_id = azurerm_virtual_network.spoke.id
}

# hub-network.tf
resource "azurerm_resource_group" "hub" { name = "${var.project}-hub-rg" location = var.location tags = local.common_tags }
resource "azurerm_virtual_network" "hub" { name = "${var.project}-hub-vnet" location = azurerm_resource_group.hub.location resource_group_name = azurerm_resource_group.hub.name address_space = var.hub_address_space tags = local.common_tags }
resource "azurerm_subnet" "gateway" { name = "GatewaySubnet" resource_group_name = azurerm_resource_group.hub.name virtual_network_name = azurerm_virtual_network.hub.name address_prefixes = ["10.0.0.0/24"] }
resource "azurerm_subnet" "firewall" { count = var.enable_firewall ? 1 : 0 name = "AzureFirewallSubnet" resource_group_name = azurerm_resource_group.hub.name virtual_network_name = azurerm_virtual_network.hub.name address_prefixes = ["10.0.1.0/24"] }
resource "azurerm_subnet" "bastion" { count = var.enable_bastion ? 1 : 0 name = "AzureBastionSubnet" resource_group_name = azurerm_resource_group.hub.name virtual_network_name = azurerm_virtual_network.hub.name address_prefixes = ["10.0.2.0/24"] }
resource "azurerm_subnet" "shared" { name = "shared-services" resource_group_name = azurerm_resource_group.hub.name virtual_network_name = azurerm_virtual_network.hub.name address_prefixes = ["10.0.3.0/24"] }
# Bastion host resource "azurerm_public_ip" "bastion" { count = var.enable_bastion ? 1 : 0 name = "${var.project}-bastion-ip" location = azurerm_resource_group.hub.location resource_group_name = azurerm_resource_group.hub.name allocation_method = "Static" sku = "Standard" tags = local.common_tags }
resource "azurerm_bastion_host" "main" { count = var.enable_bastion ? 1 : 0 name = "${var.project}-bastion" location = azurerm_resource_group.hub.location resource_group_name = azurerm_resource_group.hub.name sku = "Standard"
ip_configuration { name = "bastion-ip-config" subnet_id = azurerm_subnet.bastion[0].id public_ip_address_id = azurerm_public_ip.bastion[0].id }
copy_paste_enabled = true file_copy_enabled = true tunneling_enabled = true ip_connect_enabled = true tags = local.common_tags }
